      'record': (pb.authStore.record as RecordModel?)?.toJson() ?? sessionData['record'],
    };
    file.writeAsStringSync(jsonEncode(newSessionData));
  }

  // Decode token to get exp
  final parts = newToken.split('.');
  if (parts.length != 3) {
    stderr.writeln('INVALID_SESSION');
    exit(1);
