    payload = jsonDecode(utf8.decode(payloadBytes)) as Map<String, dynamic>;
  } catch (e) {
    stderr.writeln('INVALID_SESSION');
    exit(1);
  }

  final recordId = (pb.authStore.record as RecordModel?)?.id ?? '';
  final exp = payload['exp'];

  print(recordId);
  print(exp is int ? exp : int.parse(exp.toString()));

  exit(0);
}
